(function() {
  let api
  htmx.defineExtension('json-enc', {
    init: function(apiRef) {
      api = apiRef
    },

    onEvent: function(name, evt) {
      if (name === 'htmx:configRequest') {
        evt.detail.headers['Content-Type'] = 'application/json'
      }
    },

    encodeParameters: function(xhr, parameters, elt) {
      xhr.overrideMimeType('text/json')

      const vals = api.getExpressionVars(elt)
      const object = {}

      // htmx 2.x passes a plain Object; htmx 1.x passed a FormData (which has .forEach).
      // Handle both so the extension works regardless of which API is in use.
      const addEntry = function(key, value) {
        const typedValue = Object.hasOwn(vals, key) ? vals[key] : value
        if (Object.hasOwn(object, key)) {
          if (!Array.isArray(object[key])) {
            object[key] = [object[key]]
          }
          object[key].push(typedValue)
        } else {
          object[key] = typedValue
        }
      }

      if (typeof parameters.forEach === 'function') {
        // FormData path (htmx 1.x / some htmx 2.x configurations)
        parameters.forEach(function(value, key) { addEntry(key, value) })
      } else {
        // Plain-object path (htmx 2.x default)
        Object.entries(parameters).forEach(function(entry) { addEntry(entry[0], entry[1]) })
      }

      return JSON.stringify(object)
    }
  })
})()
